#include <stdio.h>
#define MAXN 1000000
#define MAXR 500
#define MAXC 2500
int parent[MAXN], rank[MAXN], high[MAXN];
int find(int x) { return parent[x] == x ? x : (parent[x] = find(parent[x])); }
void unionSet(int x, int y) { int rootx = find(x), rooty = find(y);
if (rootx != rooty) { if (rank[rootx] > rank[rooty]) { parent[rooty] = rootx; } else if (rank[rootx] < rank[rooty]) { parent[rootx] = rooty; } else { parent[rooty] = rootx; rank[rootx]++; }} }
int main() {
int N, R, C;
scanf("%d %d %d", &N, &R, &C);
for (int i = 0; i < R*C; i++) { parent[i] = i; rank[i] = 0; high[i] = 0; }
for (int i = 0; i < N; i++) {
char op;
scanf(" %c", &op);
if (op == 'W') {
char x[3], y[3];
scanf("%s %s", x, y);
int xx = (x[0] - 'A') * 52 + x[1] - 'A';
int yy = (y[0] - 'A') * 52 + y[1] - 'A';
unionSet(xx, yy);
} else if (op == 'V') {
char x[3];
scanf("%s", x);
int xx = (x[0] - 'A') * 52 + x[1] - 'A';
high[find(xx)] = 1;
} else if (op == 'R') {
char x[3];
