import java.util.Scanner;
public class Main {
public static void main(String[] args) {
Scanner sc = new Scanner(System.in);
int N = sc.nextInt(), R = sc.nextInt(), C = sc.nextInt();
int[] parent = new int[R*C], rank = new int[R*C], high = new int[R*C];
for (int i = 0; i < R*C; i++) { parent[i] = i; rank[i] = 0; high[i] = 0; }
for (int i = 0; i < N; i++) {
char op = sc.next().charAt(0);
if (op == 'W') {
String x = sc.next(), y = sc.next();
int xx = (x.charAt(0) - 'A') * 52 + x.charAt(1) - 'A';
int yy = (y.charAt(0) - 'A') * 52 + y.charAt(1) - 'A';
unionSet(xx, yy, parent, rank);
} else if (op == 'V') {
String x = sc.next();
int xx = (x.charAt(0) - 'A') * 52 + x.charAt(1) - 'A';
high[find(xx, parent)] = 1;
} else if (op == 'R') {
String x = sc.next();
int xx = (x.charAt(0) - 'A') * 52 + x.charAt(1) - 'A';
high[find(xx, parent)] = 0;
} else if (op == 'L') {
String x = sc.next(), y = sc.next();
int xx = (x.charAt(0) - 'A') * 52 + x.charAt(1) - 'A';
int yy = (y.charAt(0) - 'A') * 52 + y.charAt(1) - 'A';
if (high[find(xx, parent)] != high[find(yy, parent)]) {
System.out.println("ON");
} else {
System.out.println("OFF");
}
}
}
}
public static int find(int x, int[] parent) { return parent[x] == x ? x : (parent[x] = find(parent[x], parent)); }
public static void unionSet(int x, int y, int[] parent, int[] rank) { int rootx = find(x, parent), rooty = find(y, parent);
if (rootx != rooty) { if (rank[rootx] > rank[rooty]) { parent[rooty] = rootx; } else if (rank[rootx] < rank[rooty]) { parent[rootx] = rooty; } else { parent[rooty] = rootx; rank[rootx]++; }} }
}

